import "container/heap"

type mergeItem struct {
    value   int
    chunkID int
}

type mergeHeap []mergeItem

func (h mergeHeap) Len() int           { return len(h) }
func (h mergeHeap) Less(i, j int) bool { return h[i].value < h[j].value }
func (h mergeHeap) Swap(i, j int)      { h[i], h[j] = h[j], h[i] }
func (h *mergeHeap) Push(x any)        { *h = append(*h, x.(mergeItem)) }
func (h *mergeHeap) Pop() any {
    old := *h
    n := len(old)
    x := old[n-1]
    *h = old[0 : n-1]
    return x
}

func sortChunks(input io.Reader, chunkSize int) ([]string, error) {
    var chunks []string
    buffer := make([]int, 0, chunkSize)
    scanner := bufio.NewScanner(input)

    for scanner.Scan() {
        val, _ := strconv.Atoi(scanner.Text())
        buffer = append(buffer, val)

        if len(buffer) >= chunkSize {
            sort.Ints(buffer)
            filename, _ := writeChunk(buffer)
            chunks = append(chunks, filename)
            buffer = buffer[:0]
        }
    }
    if len(buffer) > 0 {
        sort.Ints(buffer)
        filename, _ := writeChunk(buffer)
        chunks = append(chunks, filename)
    }
    return chunks, nil
}
